code_changes.content:
[
  {
    "file": "src/vs/editor/common/model/textModelSearch.ts",
    "line": 92,
    "severity": "critical",
    "description": "The isMultilineRegexSource function incorrectly checks for CharCode.W (\W character class). The \W pattern (non-word character) is not multiline-specific. The multiline flag should only be set for patterns containing actual line-boundary-related escapes like \n and \r. This causes regex patterns with \W to be incorrectly treated as multiline, affecting the search behavior across multiple components that depend on this function.",
    "fix_patch": "--- a/src/vs/editor/common/model/textModelSearch.ts
+++ b/src/vs/editor/common/model/textModelSearch.ts
@@ -89,7 +89,7 @@
 		}

 		const nextChCode = searchString.charCodeAt(i);
-		if (nextChCode === CharCode.n || nextChCode === CharCode.r || nextChCode === CharCode.W) {
+		if (nextChCode === CharCode.n || nextChCode === CharCode.r) {
 			return true;
 		}
 	}
"
  },
  {
    "file": "src/vs/base/common/strings.ts",
    "line": 215,
    "severity": "high",
    "description": "The wholeWord boundary check uses an incorrect regex test pattern. The expression /\\B/.test(searchString.charAt(0)) tests if a single character matches the regex pattern \B (non-word boundary position), which is impossible. charAt(0) returns a single character, not a position in context. The condition is effectively a no-op and always evaluates to true, causing word boundaries to always be added regardless of whether they are already present. This could result in duplicated word boundary markers like \b\b.",
    "fix_patch": "--- a/src/vs/base/common/strings.ts
+++ b/src/vs/base/common/strings.ts
@@ -213,11 +213,11 @@
 	}
 	if (options.wholeWord) {
-		if (!/\\B/.test(searchString.charAt(0))) {
+		if (!/\\b/.test(searchString)) {
 			searchString = '\\\\b' + searchString;
 		}
-		if (!/\\B/.test(searchString.charAt(searchString.length - 1))) {
+		if (!searchString.endsWith('\\b')) {
 			searchString = searchString + '\\\\b';
 		}
 	}
"
  },
  {
    "file": "src/vs/editor/common/languageFeatureRegistry.ts",
    "line": 208,
    "severity": "high",
    "description": "The _compareByScoreAndTime function has inverted time ordering logic. When a._time < b._time (a registered earlier), the function returns 1, causing b (later registration) to come first in the sorted order. This reverses the expected registration priority: typically, earlier registrations should have higher priority. This cross-component bug affects all language feature providers (completions, hover, diagnostics, etc.), causing later-registered providers to incorrectly take precedence over earlier ones.",
    "fix_patch": "--- a/src/vs/editor/common/languageFeatureRegistry.ts
+++ b/src/vs/editor/common/languageFeatureRegistry.ts
@@ -207,9 +207,9 @@
 	}

 	if (a._time < b._time) {
-		return 1;
+		return -1;
 	} else if (a._time > b._time) {
-		return -1;
+		return 1;
 	} else {
 		return 0;
 	}
"
  }
]

